const Session = (function() {
  let full_name: string = "";
  let role: string = "";

  let getName = function(): string {
    return full_name; // Or pull this from cookie/localStorage
  };

  let getRole = function(): string {
    return role; // Or pull this from cookie/localStorage
  };

  let setName = function(name: string): boolean {
    full_name = name;
    // Also set this in cookie/localStorage
    return full_name === name;
  };

  let setRole = function(name: string): boolean {
    role = name;
    // Also set this in cookie/localStorage
    return role === name;
  };

  return {
    getName: getName,
    setName: setName,
    getRole: getRole,
    setRole: setRole
  };
})();

export default Session;
